#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(i32)]
pub enum TinySchemeLexState {
    DEFAULT = 0,
}

// ============================================================
// Lexical Exception
// ============================================================

#[derive(Debug)]
pub struct TinySchemeLexicalException {
    pub line: i32,
    pub column: i32,
    pub message: String,
}

impl std::fmt::Display for TinySchemeLexicalException {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "lexical error at {}:{}: {}", self.line, self.column, self.message)
    }
}

impl std::error::Error for TinySchemeLexicalException {}

