const UNMASK_2_0: u32 = 0x001f_c07f;
const UNMASK_4_2_0: u32 = 0xf01f_c07f;

struct DataReader<'a> {
    data: &'a [u8],
    pos: usize,
}

impl<'a> DataReader<'a> {
    fn new(data: &'a [u8]) -> Self {
        Self { data, pos: 0 }
    }

    fn read_byte(&mut self) -> u8 {
        let b = self.data[self.pos];
        self.pos += 1;
        b
    }

    fn read_varint(&mut self) -> i32 {
        let mut a = self.data[self.pos] as u32;
        self.pos += 1;
        if (a & 0x80) == 0 {
            return a as i32;
        }

        let mut b = self.data[self.pos] as u32;
        self.pos += 1;
        if (b & 0x80) == 0 {
            a &= UNMASK_2_0;
            a <<= 7;
            return (a | b) as i32;
        }

        a = (a << 14) | (self.data[self.pos] as u32);
        self.pos += 1;
        if (a & 0x80) == 0 {
            a &= UNMASK_4_2_0;
            b &= UNMASK_2_0;
            b <<= 7;
            return (a | b) as i32;
        }

        a &= UNMASK_4_2_0;
        b = (b << 14) | (self.data[self.pos] as u32);
        self.pos += 1;
        if (b & 0x80) == 0 {
            b &= UNMASK_4_2_0;
            a <<= 7;
            return (a | b) as i32;
        }

        b &= UNMASK_4_2_0;
        let v = a.wrapping_shl(11) | b.wrapping_shl(4) | ((self.data[self.pos] as u32) & 0xf);
        self.pos += 1;
        v as i32
    }
}

