fn static_init() -> ScannerData {
    let mut r = DataReader::new(SCANNER_DATA);

    let state_num = r.read_varint();
    let _input_num = r.read_varint();
    let dead_state = r.read_varint();

    let accept_count = r.read_varint();
    let mut accepts = vec![false; state_num as usize];
    for _ in 0..accept_count {
        let s = r.read_varint();
        accepts[s as usize] = true;
    }

    let mut fa_table = vec![-1i32; state_num as usize];
    for s in 0..state_num as usize {
        if accepts[s] {
            fa_table[s] = r.read_varint();
        }
    }

    let ttm = r.read_byte();

    assert_eq!(ttm, 1);
    let mut relation = Vec::with_capacity(state_num as usize);
    for _ in 0..state_num {
        let mut row = vec![dead_state; _input_num as usize];
        let count = r.read_varint();
        for _ in 0..count {
            let inp = r.read_varint();
            let dest = r.read_varint();
            row[inp as usize] = dest;
        }
        relation.push(row);
    }


    let opt_top = r.read_varint();
    let mut opt_cmap = vec![0i32; (opt_top + 1) as usize];
    let range_cnt = r.read_varint();
    for _ in 0..range_cnt {
        let from = r.read_varint();
        let to = r.read_varint();
        let cc = r.read_varint();
        for c in from..=to {
            opt_cmap[c as usize] = cc;
        }
    }

    let lex_state_num = r.read_varint();
    let mut lex_states = vec![0i32; lex_state_num as usize];
    for i in 0..lex_state_num as usize {
        lex_states[i] = r.read_varint();
    }
    let default_lex_state = r.read_varint();

    let mut skip = vec![false; 10];
    let mut tokens = vec![0i32; 10];
    tokens[0] = TinySchemeTokenType::LPAREN as i32;
    tokens[1] = TinySchemeTokenType::RPAREN as i32;
    tokens[2] = TinySchemeTokenType::TRUE as i32;
    tokens[3] = TinySchemeTokenType::FALSE as i32;
    tokens[4] = TinySchemeTokenType::NIL as i32;
    tokens[5] = TinySchemeTokenType::INTEGER as i32;
    tokens[6] = TinySchemeTokenType::STRING as i32;
    tokens[7] = TinySchemeTokenType::SYMBOL as i32;
    skip[8] = true;
    tokens[9] = TinySchemeTokenType::EOI as i32;

    ScannerData {
        accepts, fa_table,

        relation, dead_state,

        opt_top, opt_cmap,
        lex_states, default_lex_state,
        skip, tokens,
    }
}

static DATA: OnceLock<ScannerData> = OnceLock::new();

fn get_data() -> &'static ScannerData {
    DATA.get_or_init(static_init)
}


// ============================================================
// Non-optimized character class lookup (binary search)
// ============================================================

fn lookup_cc(cp: i32) -> i32 {
    // (from, to, char_class) sorted by from
    const RANGES: &[(i32, i32, i32)] = &[
        (65536, 1114111, 41),
    ];
    let mut lo: usize = 0;
    let mut hi: usize = RANGES.len();
    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        let (from, to, cc) = RANGES[mid];
        if cp < from {
            hi = mid;
        } else if cp > to {
            lo = mid + 1;
        } else {
            return cc;
        }
    }
    0
}


// ============================================================
// Scanner
// ============================================================

pub struct TinySchemeScanner {
    text: Vec<char>,
    pos: usize,
    token_start: usize,
    last_accepted_pos: i64,
    current_line: i32,
    current_column: i32,
    current_line_state: i32,
    token_line: i32,
    token_column: i32,
    token_line_state: i32,
    tab_width: i32,
    initial_state: i32,
}

impl TinySchemeScanner {
    pub fn new(input: &str) -> Self {
        let d = get_data();
        let initial_state = d.lex_states[d.default_lex_state as usize];
        Self {
            text: input.chars().collect(),
            pos: 0,
            token_start: 0,
            last_accepted_pos: -1,
            current_line: 1,
            current_column: 1,
            current_line_state: 0,
            token_line: 0,
            token_column: 0,
            token_line_state: 0,
            tab_width: 1,
            initial_state,
        }
    }

    pub fn text(&self) -> String {
        assert!(self.last_accepted_pos >= 0, "invalid state: call next() first");
        self.text[self.token_start..self.last_accepted_pos as usize]
            .iter().collect()
    }

    pub fn line(&self) -> i32 { self.token_line }

    pub fn column(&self) -> i32 { self.token_column }

    pub fn set_lex_state(&mut self, lex_id: i32) {
        self.initial_state = get_data().lex_states[lex_id as usize];
    }

    pub fn set_tab_width(&mut self, tab_width: i32) {
        self.tab_width = tab_width;
    }

    fn read_code_point(&mut self) -> i32 {
        if self.pos >= self.text.len() {
            return -1;
        }
        let cp = self.text[self.pos] as i32;
        self.pos += 1;

        if self.current_line_state == 0 {
            if cp == 0x0D {
                self.current_line_state = 1;
                self.current_line += 1;
                self.current_column = 1;
            } else if cp == 0x0A {
                self.current_line += 1;
                self.current_column = 1;
            } else if cp == 0x09 {
                let tw = self.tab_width;
                self.current_column = (self.current_column - 1) / tw * tw + tw + 1;
            } else {
                self.current_column += 1;
            }
        } else {
            if cp == 0x0D {
                self.current_line += 1;
                self.current_column = 1;
            } else if cp == 0x0A {
                self.current_line_state = 0;
            } else if cp == 0x09 {
                self.current_line_state = 0;
                let tw = self.tab_width;
                self.current_column = (self.current_column - 1) / tw * tw + tw + 1;
            } else {
                self.current_line_state = 0;
                self.current_column += 1;
            }
        }
        cp
    }

    pub fn next(&mut self) -> Result<TinySchemeTokenType, TinySchemeLexicalException> {
        let d = get_data();
        let accepts = &d.accepts;
        let fa_table = &d.fa_table;
        let opt_top = d.opt_top;
        let opt_cmap = &d.opt_cmap;
        let skip = &d.skip;
        let tokens = &d.tokens;

        let relation = &d.relation;
        let dead_state = d.dead_state;


        loop {
            let mut state = self.initial_state;
            self.token_start = self.pos;
            self.token_line = self.current_line;
            self.token_column = self.current_column;
            self.token_line_state = self.current_line_state;
            self.last_accepted_pos = -1;
            let mut last_accepted_state: i32 = -1;
            let mut last_accepted_line: i32 = -1;
            let mut last_accepted_column: i32 = -1;
            let mut last_accepted_line_state: i32 = -1;

            if accepts[state as usize] {
                last_accepted_state = state;
                self.last_accepted_pos = self.pos as i64;
                last_accepted_line = self.current_line;
                last_accepted_column = self.current_column;
                last_accepted_line_state = self.current_line_state;
            }

            loop {
                let ch = self.read_code_point();
                if ch == -1 { break; }

                let cc = if ch <= opt_top {
                    opt_cmap[ch as usize]
                } else {
                    lookup_cc(ch)
                };


                state = relation[state as usize][cc as usize];
                if state == dead_state { break; }
                if accepts[state as usize] {
                    last_accepted_state = state;
                    self.last_accepted_pos = self.pos as i64;
                    last_accepted_line = self.current_line;
                    last_accepted_column = self.current_column;
                    last_accepted_line_state = self.current_line_state;
                }

            }

            if last_accepted_state != -1 {
                self.pos = self.last_accepted_pos as usize;
                self.current_line = last_accepted_line;
                self.current_column = last_accepted_column;
                self.current_line_state = last_accepted_line_state;
                let fa = fa_table[last_accepted_state as usize];
                if skip[fa as usize] {
                    continue;
                }
                return Ok(TinySchemeTokenType::from_i32(tokens[fa as usize]));
            } else if self.token_start == self.pos {
                self.last_accepted_pos = self.pos as i64;
                return Ok(TinySchemeTokenType::EOI);
            } else {
                self.pos = self.token_start;
                self.current_line = self.token_line;
                self.current_column = self.token_column;
                self.current_line_state = self.token_line_state;
                return Err(TinySchemeLexicalException {
                    line: self.token_line,
                    column: self.token_column,
                    message: "syntax error".to_string(),
                });
            }
        }
    }
}
